changeSet.sql:
CREATE TABLE IF NOT EXISTS specialist_profile ( id VARCHAR(36) PRIMARY KEY, user_id VARCHAR(36) NOT NULL UNIQUE, category VARCHAR(128) NOT NULL, description TEXT, price_from INTEGER, price_to INTEGER, active BOOLEAN NOT NULL, rating DOUBLE PRECISION NOT NULL, reviews_count INTEGER NOT NULL );
CREATE INDEX IF NOT EXISTS idx_specialist_profile_active ON specialist_profile (active);
CREATE INDEX IF NOT EXISTS idx_specialist_profile_category ON specialist_profile (category);
